import json
from typing import Optional, Any

def run(doc: dict, db: Any = None, config: Optional[dict] = None) -> dict:
    raw_json = doc.get("__raw_json")

    if not raw_json:
        raise ValueError("Missing '__raw_json' in document")

    try:
        parsed = json.loads(raw_json)
    except (ValueError, TypeError):
        raise ValueError("Invalid JSON string provided in '__raw_json'")

    return parsed
